import * as React from "react"
import { cn } from "@/lib/utils"
// @ts-ignore
import { Vector as VectorLayer } from 'ol/layer'
// @ts-ignore
import { Vector as VectorSource } from 'ol/source'
// @ts-ignore
import { KML } from 'ol/format'
import type Map from 'ol/Map'
import { useMap } from '../gis-map-core/gis-map-core'
import JSZip from 'jszip'
import { getMapCoordinateType } from '../gis-shared-utils/gis-shared-utils'

// Helper to load KMZ (ported from source)
const loadRemoteKMZ = async (kmzUrl: string) => {
    try {
        const response = await fetch(kmzUrl);
        if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);

        const arrayBuffer = await response.arrayBuffer();
        const zip = await JSZip.loadAsync(arrayBuffer);

        const kmlFile = Object.keys(zip.files).find(name => name.endsWith('.kml'));
        if (!kmlFile) throw new Error('KMZ中未找到KML文件');

        const kmlContent = await zip.file(kmlFile)?.async('text');
        return kmlContent;
    } catch (error) {
        console.error('加载KMZ失败:', error);
        throw error;
    }
};

export interface LayerBase {
    opacity?: number
    zIndex?: number
    maxResolution?: number
    minResolution?: number
    maxZoom?: number
    minZoom?: number
}

export interface KmzProps {
    source?: string
    coordinateType?: string
    kmzFile?: string
    title?: string
    layerBase?: LayerBase
    display?: boolean
    className?: string
    cellKey?: string
    map?: Map | null
}

const Kmz = React.forwardRef<HTMLDivElement, KmzProps>(
    (
        {
            className,
            cellKey,
            source: sourceUrl,
            kmzFile,
            coordinateType,
            title = 'kmz',
            layerBase,
            display = true,
            map: mapProp,
            ...props
        },
        ref
    ) => {
        const contextMap = useMap()
        const map = mapProp || contextMap
        const layerRef = React.useRef<any>(null)

        const { opacity, zIndex, maxResolution, minResolution, maxZoom, minZoom } = layerBase || {}

        // Load and Create Layer
        React.useEffect(() => {
            if (!map) return

            let isCancelled = false;

            const loadAndAddLayer = async () => {
                try {
                    const rawUrl = kmzFile || sourceUrl
                    if (!rawUrl) return

                    let kmzUrl = rawUrl
                    if (!rawUrl.startsWith('http') && typeof window !== 'undefined') {
                        kmzUrl = window.location.origin + (rawUrl.startsWith('/') ? '' : '/') + rawUrl
                    }

                    const mapCoordinateType = getMapCoordinateType(map)

                    // Load KML content from KMZ
                    const kmlContent = await loadRemoteKMZ(kmzUrl)

                    if (isCancelled) return

                    // Create Layer
                    const source = new VectorSource({
                        format: new KML({
                            extractStyles: true,
                            showPointNames: false,
                            dataProjection: coordinateType,
                            featureProjection: mapCoordinateType
                        }),
                        // Use features read from content
                        features: new KML().readFeatures(kmlContent, {
                            dataProjection: coordinateType,
                            featureProjection: mapCoordinateType
                        })
                    })

                    const layer = new VectorLayer({
                        id: cellKey,
                        title,
                        source: source,
                        opacity: opacity || 1,
                        zIndex,
                        maxResolution,
                        minResolution,
                        maxZoom, // Logic from source doesn't strictly pass all these to constructor in kmz.js but uses useLayerProperties. I'll add them here for initial state.
                        minZoom,
                        properties: {
                            layerType: 'kmz',
                            cellKey,
                            title
                        }
                    } as any)

                    if (layerRef.current) {
                        map.removeLayer(layerRef.current)
                    }

                    layerRef.current = layer
                    layer.setVisible(display)
                    map.addLayer(layer)

                } catch (error: any) {
                    console.error('加载KMZ图层失败:', error)
                    // alert('加载KMZ文件失败: ' + error?.message) // Optional: replicate alert
                }
            }

            loadAndAddLayer()

            return () => {
                isCancelled = true
                if (layerRef.current && map) {
                    map.removeLayer(layerRef.current)
                }
            }
        }, [map, sourceUrl, kmzFile, coordinateType, cellKey, title]) // Re-load if source changes

        // Update Visibility and Properties (Dynamic updates)
        React.useEffect(() => {
            const layer = layerRef.current
            if (!layer) return

            layer.setVisible(display)
            if (opacity !== undefined) layer.setOpacity(opacity)
            if (zIndex !== undefined) layer.setZIndex(zIndex)
            if (maxResolution !== undefined) layer.setMaxResolution(maxResolution)
            if (minResolution !== undefined) layer.setMinResolution(minResolution)
            if (maxZoom !== undefined) layer.setMaxZoom(maxZoom)
            if (minZoom !== undefined) layer.setMinZoom(minZoom)

        }, [display, opacity, zIndex, maxResolution, minResolution, maxZoom, minZoom])

        return (
            <div
                ref={ref}
                className={cn("kmz-layer", className)}
                style={{ display: 'none' }}
                data-cell-key={cellKey}
                {...props}
            />
        )
    }
)

Kmz.displayName = "Kmz"

export { Kmz }

import * as React from "react"
import { cn } from "@/lib/utils"
import Map from 'ol/Map'
import View from 'ol/View'
import TileLayer from 'ol/layer/Tile'
import XYZ from 'ol/source/XYZ'
import { fromLonLat, transformExtent } from 'ol/proj'
import { Zoom, ScaleLine, defaults as defaultControls } from 'ol/control'
import 'ol/ol.css'

// Map Context 用于向子组件传递 map 实例
export interface MapContextValue {
  map: Map | null
}

export const MapContext = React.createContext<MapContextValue>({ map: null })

// Hook 用于获取 map 实例
export const useMap = () => {
  const context = React.useContext(MapContext)
  return context.map
}

export interface ViewOptions {
  position?: {
    center?: [number, number]
    pick?: boolean
  }
  resetCenter?: {
    tableData?: Array<{ id: string; _table: string }>
  }
  zoom?: number
  maxZoom?: number
  minZoom?: number
  rotation?: number
  recordRotationActive?: boolean
  resolution?: number
  animation?: boolean
  duration?: number
}

export interface ZoomOption {
  show?: boolean
  zoomInTipLabel?: string
  zoomOutTipLabel?: string
  minZoom?: number
  maxZoom?: number
}

export interface ScaleLineOption {
  show?: boolean
  minWidth?: number
  units?: 'metric' | 'us' | 'nautical' | 'imperial' | 'degrees'
  steps?: number
  bar?: boolean
  text?: boolean
}

export interface ExtentOption {
  westLon?: number
  southLat?: number
  eastLon?: number
  northLat?: number
}

export interface MapContainerProps {
  /**
   * 视图配置
   */
  viewOptions?: ViewOptions
  /**
   * 缩放控件配置
   */
  zoomOption?: ZoomOption
  /**
   * 比例尺配置
   */
  scaleLine?: ScaleLineOption
  /**
   * 拖拽边界范围
   */
  extentOption?: ExtentOption
  /**
   * 宽度
   */
  width?: number | string
  /**
   * 高度
   */
  height?: number | string
  /**
   * CSS 类名
   */
  className?: string
  /**
   * 单元格唯一标识
   */
  cellKey?: string
  /**
   * 子元素
   */
  children?: React.ReactNode
}

// 默认中心点坐标 (北京)
const DEFAULT_CENTER: [number, number] = [116.391, 39.9042]

// 高德地图瓦片图层
const createTileLayer = () => {
  return new TileLayer({
    source: new XYZ({
      url: 'http://wprd0{1-4}.is.autonavi.com/appmaptile?lang=zh_cn&size=1&style=7&x={x}&y={y}&z={z}',
      crossOrigin: 'anonymous',
    }),
  })
}

const MapContainer = React.forwardRef<HTMLDivElement, MapContainerProps>(
  (
    {
      className,
      viewOptions = {
        position: {
          center: DEFAULT_CENTER,
          pick: false
        },
        zoom: 10,
        maxZoom: 18,
        minZoom: 3,
        rotation: 0,
        recordRotationActive: false,
        animation: true,
        duration: 1000
      },
      zoomOption = {
        show: true,
        zoomInTipLabel: '放大',
        zoomOutTipLabel: '缩小',
        minZoom: 3,
        maxZoom: 18
      },
      scaleLine = {
        show: true,
        bar: false,
        text: false
      },
      extentOption,
      width = '100%',
      height = '100%',
      cellKey,
      children,
      ...props
    },
    ref
  ) => {
    const containerRef = React.useRef<HTMLDivElement>(null)
    const mapRef = React.useRef<HTMLDivElement>(null)
    const [mapInstance, setMapInstance] = React.useState<Map | null>(null)
    const [mapReady, setMapReady] = React.useState(false)

    // 合并 ref
    React.useImperativeHandle(ref, () => containerRef.current as HTMLDivElement)

    // 获取配置值
    const center = viewOptions?.position?.center || DEFAULT_CENTER
    const zoom = viewOptions?.zoom ?? 10
    const maxZoom = viewOptions?.maxZoom ?? 18
    const minZoom = viewOptions?.minZoom ?? 3
    const rotation = viewOptions?.rotation ?? 0
    const animation = viewOptions?.animation ?? true
    const duration = viewOptions?.duration ?? 1000

    // 初始化地图
    React.useEffect(() => {
      if (!mapRef.current || mapInstance) return

      // 构建视图配置
      const viewConfig: Record<string, unknown> = {
        center: fromLonLat(center),
        zoom,
        maxZoom,
        minZoom,
        rotation: (rotation * Math.PI) / 180, // 角度转弧度
      }

      // 处理边界范围
      if (extentOption) {
        const { northLat, eastLon, southLat, westLon } = extentOption
        if (northLat && eastLon && southLat && westLon) {
          const fixedExtent = [
            Math.min(westLon, eastLon),
            southLat,
            Math.max(westLon, eastLon),
            northLat
          ]
          viewConfig.extent = transformExtent(fixedExtent, 'EPSG:4326', 'EPSG:3857')
        }
      }

      // 创建地图实例
      const map = new Map({
        target: mapRef.current,
        layers: [createTileLayer()],
        view: new View(viewConfig),
        controls: defaultControls({
          zoom: false,
          attribution: false,
          rotate: false,
        }),
      })

      // 添加缩放控件
      if (zoomOption?.show) {
        map.addControl(new Zoom({
          zoomInTipLabel: zoomOption.zoomInTipLabel || '放大',
          zoomOutTipLabel: zoomOption.zoomOutTipLabel || '缩小',
        }))
      }

      // 添加比例尺
      if (scaleLine?.show) {
        map.addControl(new ScaleLine({
          units: scaleLine.units || 'metric',
          bar: scaleLine.bar || false,
          text: scaleLine.text || false,
          minWidth: scaleLine.minWidth,
          steps: scaleLine.steps,
        }))
      }

      setMapInstance(map)
      setMapReady(true)

      // 监听容器大小变化
      const resizeObserver = new ResizeObserver(() => {
        map.updateSize()
      })
      if (mapRef.current) {
        resizeObserver.observe(mapRef.current)
      }

      return () => {
        resizeObserver.disconnect()
        if (map) {
          map.setTarget(undefined)
          setMapInstance(null)
        }
      }
    }, [])

    // 更新中心位置
    React.useEffect(() => {
      if (!mapInstance || !mapReady) return
      const view = mapInstance.getView()
      const newCenter = fromLonLat(center)

      if (animation) {
        view.animate({ center: newCenter, duration })
      } else {
        view.setCenter(newCenter)
      }
    }, [center[0], center[1], mapReady])

    // 更新缩放级别
    React.useEffect(() => {
      if (!mapInstance || !mapReady) return
      const view = mapInstance.getView()

      if (animation) {
        view.animate({ zoom, duration })
      } else {
        view.setZoom(zoom)
      }
    }, [zoom, mapReady])

    // 更新最大/最小缩放
    React.useEffect(() => {
      if (!mapInstance || !mapReady) return
      const view = mapInstance.getView()
      view.setMaxZoom(maxZoom)
      view.setMinZoom(minZoom)
    }, [maxZoom, minZoom, mapReady])

    // 更新旋转角度
    React.useEffect(() => {
      if (!mapInstance || !mapReady) return
      const view = mapInstance.getView()
      const radians = (rotation * Math.PI) / 180

      if (animation) {
        view.animate({ rotation: radians, duration })
      } else {
        view.setRotation(radians)
      }
    }, [rotation, mapReady])

    // 更新缩放控件
    React.useEffect(() => {
      if (!mapInstance || !mapReady) return
      const controls = mapInstance.getControls().getArray()
      const zoomControl = controls.find((c: unknown) => c instanceof Zoom)

      if (!zoomOption?.show && zoomControl) {
        mapInstance.removeControl(zoomControl)
      } else if (zoomOption?.show && !zoomControl) {
        mapInstance.addControl(new Zoom({
          zoomInTipLabel: zoomOption.zoomInTipLabel || '放大',
          zoomOutTipLabel: zoomOption.zoomOutTipLabel || '缩小',
        }))
      }
    }, [zoomOption?.show, mapReady, mapInstance])

    // 更新比例尺
    React.useEffect(() => {
      if (!mapInstance || !mapReady) return
      const controls = mapInstance.getControls().getArray()
      const scaleLineControl = controls.find((c: unknown) => c instanceof ScaleLine)

      if (scaleLineControl) {
        mapInstance.removeControl(scaleLineControl)
      }

      if (scaleLine?.show) {
        mapInstance.addControl(new ScaleLine({
          units: scaleLine.units || 'metric',
          bar: scaleLine.bar || false,
          text: scaleLine.text || false,
          minWidth: scaleLine.minWidth,
          steps: scaleLine.steps,
        }))
      }
    }, [scaleLine?.show, scaleLine?.units, scaleLine?.bar, scaleLine?.text, mapReady, mapInstance])

    return (
      <div
        ref={containerRef}
        className={cn(
          "relative overflow-hidden",
          className
        )}
        style={{
          width: typeof width === 'number' ? `${width}px` : width,
          height: typeof height === 'number' ? `${height}px` : height
        }}
        data-cell-key={cellKey}
        {...props}
      >
        {/* OpenLayers 地图容器 */}
        <div 
          ref={mapRef} 
          className="absolute inset-0"
          style={{ width: '100%', height: '100%' }}
        />

        {/* 子元素容器 - 通过 Context 传递 map 实例 */}
        {children && (
          <MapContext.Provider value={{ map: mapInstance }}>
            <div className="absolute inset-0 pointer-events-none z-10">
              <div className="pointer-events-auto">
                {mapReady ? children : null}
              </div>
            </div>
          </MapContext.Provider>
        )}
      </div>
    )
  }
)

MapContainer.displayName = "MapContainer"

export { MapContainer }

import Map from 'ol/Map'
import gcoord from 'gcoord'
import { Vector as VectorSource } from 'ol/source'

// 坐标系映射表
export const COORD_SYSTEM_MAP: Record<string, string> = {
    // WGS84系列
    WGS84: 'EPSG:4326',
    WGS1984: 'EPSG:4326',
    EPSG4326: 'EPSG:4326',
    'EPSG:4326': 'EPSG:4326',

    // 火星坐标系
    GCJ02: 'GCJ02',
    AMap: 'GCJ02',

    // 百度坐标系
    BD09: 'BD09',
    BD09LL: 'BD09',
    Baidu: 'BD09',
    BMap: 'BD09',
    BD09MC: 'BD09MC',
    BD09Meter: 'BD09MC',

    // Web墨卡托
    EPSG3857: 'EPSG:3857',
    'EPSG:3857': 'EPSG:3857',
    EPSG900913: 'EPSG:3857',
    EPSG102100: 'EPSG:3857',
    WebMercator: 'EPSG:3857',
    WM: 'EPSG:3857'
}

// 递归转换GeoJSON坐标
export const transformGeoJSON = (geojson: any, from: string, to: string) => {
    const clone = JSON.parse(JSON.stringify(geojson))
    const transform = (coords: any): any => {
        if (!Array.isArray(coords)) return coords
        if (typeof coords[0] === 'number') {
            // @ts-ignore
            return gcoord.transform(coords, gcoord[from], gcoord[to])
        }
        return coords.map(transform)
    }

    clone.features?.forEach((f: any) => {
        if (f.geometry?.coordinates) {
            f.geometry.coordinates = transform(f.geometry.coordinates)
        }
    })
    return clone
}

// 获取地图坐标系类型
export const getMapCoordinateType = (map: Map | null) => {
    if (!map || !map.getView) {
        return 'EPSG:3857'
    }
    const view = map.getView()
    const projection = view.getProjection()
    return projection.getCode()
}

/**
 * 创建矢量数据源（智能坐标系转换，复刻 legacy 逻辑）
 */
export const createVectorSource = (
    dataProjection: string | undefined, // 用户配置的坐标系 (e.g. GCJ02)
    format: any,
    url: string,
    map: Map | null
) => {
    const mapProjection = getMapCoordinateType(map)
    const normalizedDataProj = COORD_SYSTEM_MAP[dataProjection || ''] || dataProjection
    const normalizedMapProj = COORD_SYSTEM_MAP[mapProjection] || mapProjection

    return new VectorSource({
        format,
        url,
        loader: async function (this: VectorSource, _extent, _resolution, _projection, success, failure) {
            try {
                const response = await fetch(url)
                if (!response.ok) {
                    throw new Error(`HTTP ${response.status} ${response.statusText}`)
                }
                const geojson = await response.json()

                let finalData = geojson
                let finalDataProjection = normalizedDataProj

                // 加密坐标系 -> WGS84
                if (normalizedDataProj && ['GCJ02', 'BD09', 'BD09MC'].includes(normalizedDataProj)) {
                    finalData = transformGeoJSON(geojson, normalizedDataProj, 'WGS84')
                    finalDataProjection = 'EPSG:4326' // WGS84 is 4326
                }

                // OpenLayers自动转换到目标坐标系
                const features = format.readFeatures(finalData, {
                    dataProjection: finalDataProjection || 'EPSG:4326', // Default to 4326 if not specified
                    featureProjection: normalizedMapProj
                })

                this.addFeatures(features)
                if (success) success(features)
            } catch (error) {
                console.error('数据加载失败:', error)
                if (failure) failure()
            }
        }
    })
}

// Helper to convert hex to rgba
export const hexToRgba = (hex: string, opacity: number | undefined) => {
    if (!hex) return hex;
    let c: string[];
    if (/^#([A-Fa-f0-9]{3}){1,2}$/.test(hex)) {
        c = hex.substring(1).split('');
        if (c.length == 3) {
            c = [c[0], c[0], c[1], c[1], c[2], c[2]];
        }
        const val = parseInt(c.join(''), 16);
        return 'rgba(' + [(val >> 16) & 255, (val >> 8) & 255, val & 255].join(',') + ',' + (opacity === undefined ? 1 : opacity) + ')';
    }
    return hex;
}
